  import sailpoint.object.Application;
  import sailpoint.object.TaskDefinition;
import sailpoint.object.Filter;
import sailpoint.object.Identity;
import sailpoint.object.Link;
import sailpoint.object.QueryOptions;
import sailpoint.object.TaskResult;
import sailpoint.api.Terminator;
import java.util.Date;
import java.text.SimpleDateFormat; 
import sailpoint.tools.Util;
import sailpoint.object.Filter.MatchMode;

import org.apache.commons.logging.Log;
import org.apache.commons.logging.LogFactory;

  //added to get identities from samAcccountName
 
 //Filter valueFilter = Filter.like("name","AA-", Filter.MatchMode.START);
 Filter typeFilter = Filter.eq("type","AccountAggregation");
 QueryOptions qo = new QueryOptions();
 //qo.add(valueFilter);
 qo.add(typeFilter);
 List taskDefs = context.getObjects(TaskDefinition.class, qo);
 
 Iterator it = taskDefs.iterator();
 
 StringBuilder returnString = new StringBuilder();
 count = 0;
 
 while ((null != it) && (it.hasNext())) {

   TaskDefinition td = it.next();
   //add <entry key="noResetNeedsRefresh" value="true"/> to all taskDefinitions
   td.setArgument("noResetNeedsRefresh", "true"); 
   context.saveObject(td);
   context.commitTransaction();
   
   count++;
}

return "taskDefinitions updated: " + count;
